import React from "react";

export default function Topbar({ title, urgentCount, availableCount, onSeed, seeding }) {
  return (
    <div className="topbar">
      <span className="topbar-title">{title}</span>
      <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
        {urgentCount > 0 && <span className="badge badge-red">⚠ {urgentCount} urgent</span>}
        <span className="badge badge-green">{availableCount} available</span>
        {onSeed && (
          <button className="btn btn-sm" onClick={onSeed} disabled={seeding} style={{ fontSize: 11 }}>
            {seeding ? "Seeding..." : "⚡ Seed Sample Data"}
          </button>
        )}
      </div>
    </div>
  );
}
